{
  "query": "mutation Signup($input: SignupInput!) { signup(input: $input) { id username email created_at updated_at } }",
  "variables": {
    "input": {
      "username": "student_01",
      "email": "student01@example.com",
      "password": "Pass1234"
    }
  }
}

{
  "query": "query Login($username_or_email: String!, $password: String!) { login(username_or_email: $username_or_email, password: $password) { token user { id username email } } }",
  "variables": {
    "username_or_email": "student_01",
    "password": "Pass1234"
  }
}

{
  "query": "query { getAllEmployees { eid first_name last_name email gender designation salary date_of_joining department employee_photo created_at updated_at } }"
}

{
  "query": "mutation AddEmployee($input: AddEmployeeInput!) { addEmployee(input: $input) { eid first_name last_name employee_photo } }",
  "variables": {
    "input": {
      "eid": "E1001",
      "first_name": "John",
      "last_name": "Doe",
      "email": "john.doe@example.com",
      "gender": "Male",
      "designation": "Developer",
      "salary": 5000,
      "date_of_joining": "2026-01-01",
      "department": "Engineering",
      "employee_photo": "https://images.unsplash.com/photo-1500648767791-00dcc994a43e"
    }
  }
}

{
  "query": "query SearchByEid($eid: String!) { searchEmployeeByEid(eid: $eid) { eid first_name last_name email designation department employee_photo } }",
  "variables": {
    "eid": "E1001"
  }
}

{
  "query": "mutation UpdateEmployee($eid: String!, $input: UpdateEmployeeByEidInput!) { updateEmployeeByEid(eid: $eid, input: $input) { eid designation department salary } }",
  "variables": {
    "eid": "E1001",
    "input": {
      "designation": "Senior Developer",
      "department": "Engineering",
      "salary": 7000
    }
  }
}

{
  "query": "query SearchByDesignation($designation: String, $department: String) { searchEmployeeByDesignationOrDepartment(designation: $designation, department: $department) { eid first_name designation department } }",
  "variables": {
    "designation": "Developer",
    "department": null
  }
}
